/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to a PDF file. LoadWWPContext.Call(&Context)
Do 'LoadGridState'
&Title = "Lista de Lançamento Pedidos"
//Report Template Source Header &AppName = "DVelop Software Solutions" &Phone = !"+1 550 8923" &Mail = !"info@mail.com" &Website = !"http://www.web.com" &AddressLine1 = !"French Boulevard 2859" &AddressLine2 = !"Downtown" &AddressLine3 = !"Paris, France" Print printTitle End Footer &PageInfo = "Page: " + &Page.ToString().Trim() &DateInfo = "Date: " + &Today.ToFormattedString() Print printFooter End
Do 'PrintFilters'
Do 'PrintColumnTitles'
Do 'PrintData'
Do 'PrintFooter'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'PrintFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not &FilCod.IsEmpty()
print printBlockFilterFilCod EndIf If not &PedFatFilCod.IsEmpty()
print printBlockFilterPedFatFilCod EndIf If not &FilPedCod.IsEmpty() print printBlockFilterFilPedCod EndIf If not &PedSts.IsEmpty() &FilterPedStsValueDescription = &PedSts.EnumerationDescription()
print printBlockFilterPedSts EndIf If not &PedNovStsCod.IsEmpty()
print printBlockFilterPedNovStsCod EndIf If not &PedCliCod.IsEmpty() print printBlockFilterPedCliCod EndIf If not &PedCliRaz.IsEmpty() print printBlockFilterPedCliRaz EndIf If not &PedStsFin.IsEmpty() &FilterPedStsFinValueDescription = &PedStsFin.EnumerationDescription()
print printBlockFilterPedStsFin EndIf If not &PedNovStsFinCod.IsEmpty()
print printBlockFilterPedNovStsFinCod EndIf If not &PedDtaEms.IsEmpty() print printBlockFilterPedDtaEms EndIf If not &PedDtaEms_To.IsEmpty() &PedDtaEms_To_Description = format('%1 (%2)', "E.", " - ") print printBlockFilterPedDtaEms_To EndIf If not &LctTip.IsEmpty() &FilterLctTipValueDescription = &LctTip.EnumerationDescription()
print printBlockFilterLctTip EndIf If not &LctAtuSal.IsEmpty() &FilterLctAtuSalValueDescription = &LctAtuSal.EnumerationDescription()
print printBlockFilterLctAtuSal EndIf If not &PedBlq.IsEmpty() &FilterPedBlqValueDescription = &PedBlq.EnumerationDescription()
print printBlockFilterPedBlq EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'LCTCOD' &LctCod1.FromString(&GridStateDynamicFilter.Value) If not &LctCod1.IsEmpty() &LctCod = &LctCod1 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector1 = !'PEDDTAFAT' &PedDtaFat1.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat1.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat1 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To1.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To1 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector1 = !'PEDVENCOD' &PedVenCod1.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod1.IsEmpty() &PedVenCod = &PedVenCod1 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector1 = !'PEDNUM' &PedNum1.FromString(&GridStateDynamicFilter.Value) If not &PedNum1.IsEmpty() &PedNum = &PedNum1 print printBlockFilterPedNum EndIf Case &DynamicFiltersSelector1 = !'PEDCLICIDNOM' &PedCliCidNom1.FromString(&GridStateDynamicFilter.Value) If not &PedCliCidNom1.IsEmpty() &PedCliCidNom = &PedCliCidNom1 print printBlockFilterPedCliCidNom EndIf Case &DynamicFiltersSelector1 = !'PEDCLIRATCOD' &PedCliRatCod1.FromString(&GridStateDynamicFilter.Value) If not &PedCliRatCod1.IsEmpty() &PedCliRatCod = &PedCliRatCod1 print printBlockFilterPedCliRatCod EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'LCTCOD' &LctCod2.FromString(&GridStateDynamicFilter.Value) If not &LctCod2.IsEmpty() &LctCod = &LctCod2 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector2 = !'PEDDTAFAT' &PedDtaFat2.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat2.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat2 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To2.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To2 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector2 = !'PEDVENCOD' &PedVenCod2.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod2.IsEmpty() &PedVenCod = &PedVenCod2 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector2 = !'PEDNUM' &PedNum2.FromString(&GridStateDynamicFilter.Value) If not &PedNum2.IsEmpty() &PedNum = &PedNum2 print printBlockFilterPedNum EndIf Case &DynamicFiltersSelector2 = !'PEDCLICIDNOM' &PedCliCidNom2.FromString(&GridStateDynamicFilter.Value) If not &PedCliCidNom2.IsEmpty() &PedCliCidNom = &PedCliCidNom2 print printBlockFilterPedCliCidNom EndIf Case &DynamicFiltersSelector2 = !'PEDCLIRATCOD' &PedCliRatCod2.FromString(&GridStateDynamicFilter.Value) If not &PedCliRatCod2.IsEmpty() &PedCliRatCod = &PedCliRatCod2 print printBlockFilterPedCliRatCod EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'LCTCOD' &LctCod3.FromString(&GridStateDynamicFilter.Value) If not &LctCod3.IsEmpty() &LctCod = &LctCod3 print printBlockFilterLctCod EndIf Case &DynamicFiltersSelector3 = !'PEDDTAFAT' &PedDtaFat3.FromString(&GridStateDynamicFilter.Value) &PedDtaFat_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &PedDtaFat3.IsEmpty() &FilterPedDtaFatDescription = "Faturado" &PedDtaFat = &PedDtaFat3 print printBlockFilterPedDtaFat EndIf If not &PedDtaFat_To3.IsEmpty() &FilterPedDtaFatDescription = format('%1 (%2)', "Faturado", "até") &PedDtaFat = &PedDtaFat_To3 print printBlockFilterPedDtaFat EndIf Case &DynamicFiltersSelector3 = !'PEDVENCOD' &PedVenCod3.FromString(&GridStateDynamicFilter.Value) If not &PedVenCod3.IsEmpty() &PedVenCod = &PedVenCod3 print printBlockFilterPedVenCod EndIf Case &DynamicFiltersSelector3 = !'PEDNUM' &PedNum3.FromString(&GridStateDynamicFilter.Value) If not &PedNum3.IsEmpty() &PedNum = &PedNum3 print printBlockFilterPedNum EndIf Case &DynamicFiltersSelector3 = !'PEDCLICIDNOM' &PedCliCidNom3.FromString(&GridStateDynamicFilter.Value) If not &PedCliCidNom3.IsEmpty() &PedCliCidNom = &PedCliCidNom3 print printBlockFilterPedCliCidNom EndIf Case &DynamicFiltersSelector3 = !'PEDCLIRATCOD' &PedCliRatCod3.FromString(&GridStateDynamicFilter.Value) If not &PedCliRatCod3.IsEmpty() &PedCliRatCod = &PedCliRatCod3 print printBlockFilterPedCliRatCod EndIf EndCase EndIf EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
print printBlockBeforeGrid print printBlockLines_titles
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrintData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod FilCod (PedCod) when &OrderedBy = 1 order EmpCod FilCod PedCod when &OrderedBy = 2 order EmpCod FilCod (PedDtaPrv) when &OrderedBy = 3 order EmpCod FilCod PedDtaPrv when &OrderedBy = 4 order EmpCod FilCod PedCliRaz when &OrderedBy = 5 order PedDtaEms when &OrderedBy = 6 AND &OrderedDsc = False order (PedDtaEms) when &OrderedBy = 6 AND &OrderedDsc = True order PedDtaVct when &OrderedBy = 7 AND &OrderedDsc = False order (PedDtaVct) when &OrderedBy = 7 AND &OrderedDsc = True order PedDtaFat when &OrderedBy = 8 AND &OrderedDsc = False order (PedDtaFat) when &OrderedBy = 8 AND &OrderedDsc = True
using DSwwPedidoVendaAgr(&FilCod, &PedFatFilCod, &FilPedCod, &PedSts, &PedNovStsCod, &PedCliCod , &PedCliRaz, &PedStsFin, &PedNovStsFinCod, &PedDtaEms, &PedDtaEms_To, &LctTip , &LctAtuSal, &PedBlq, &DynamicFiltersSelector1, &LctCod1, &PedDtaFat1, &PedDtaFat_To1 , &PedVenCod1, &PedNum1, &PedCliCidNom1, &PedCliRatCod1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2 , &LctCod2, &PedDtaFat2, &PedDtaFat_To2, &PedVenCod2, &PedNum2, &PedCliCidNom2 , &PedCliRatCod2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &LctCod3, &PedDtaFat3, &PedDtaFat_To3 , &PedVenCod3, &PedNum3, &PedCliCidNom3, &PedCliRatCod3) &PedNovCliRaz = iif(PedCliCodRaz_Nov.Length() > 30, Substr(PedCliCodRaz_Nov,1,30)+'...', PedCliCodRaz_Nov) &NovoStatus = trim(PedNovStsNom) If PedStsFinIsPar = true &AuxFin = 'PAR.' Else &AuxFin = UPPER(Substr(PedStsFin.EnumerationDescription(), 1,3)) Endif
Do 'BeforePrintLine' print printBlockLines_data Do 'AfterPrintLine' EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"wwPedidoVendaAgrGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"wwPedidoVendaAgrGridState")) Else &GridState.FromXml(&Session.Get(!"wwPedidoVendaAgrGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"FILCOD" &FilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDFATFILCOD" &PedFatFilCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILPEDCOD" &FilPedCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTS" &PedSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSCOD" &PedNovStsCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLICOD" &PedCliCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDCLIRAZ" &PedCliRaz.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDSTSFIN" &PedStsFin.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDNOVSTSFINCOD" &PedNovStsFinCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDDTAEMS" &PedDtaEms.FromString(&GridStateFilterValue.Value) &PedDtaEms_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"LCTTIP" &LctTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"LCTATUSAL" &LctAtuSal.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"PEDBLQ" &PedBlq.FromString(&GridStateFilterValue.Value) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
